def batch_import(config_file):
    """
    Run batch imports from a JSON configuration file.
    
    Expected config format:
    {
        "database": "etl_staging",
        "imports": [
            {
                "file": "/var/data/imports/customers.csv",
                "table": "staging_customers",
                "delimiter": ",",
                "skip_header": true
            }
        ]
    }
    """
    import json
    
    config_path = os.path.normpath(os.path.realpath(config_file))
    
    # Validate config file path
    if not os.path.isfile(config_path):
        raise FileNotFoundError(f"Config file not found: {config_path}")
    
    if not config_path.endswith('.json'):
        raise ValueError("Config file must be a JSON file.")
    
    with open(config_path, 'r') as f:
        config = json.load(f)
    
    db_name = config.get('database')
    imports = config.get('imports', [])
    
    if not db_name or not imports:
        raise ValueError("Config must contain 'database' and 'imports' fields.")
    
    connection = get_db_connection(db_name)
    
    results = []
    try:
        for i, imp in enumerate(imports, 1):
            print(f"\n{'=' * 40}")
            print(f"Processing import {i}/{len(imports)}")
            
            try:
                file_path = imp.get('file', '')
                table_name = imp.get('table', '')
                delimiter = imp.get('delimiter', ',')
                skip_header = imp.get('skip_header', True)
                enclosed_by = imp.get('enclosed_by', '"')
                line_terminator = imp.get('line_terminator', '\\n')
                
                rows = bulk_import_data(
                    connection=connection,
                    file_path=file_path,
                    table_name=table_name,
                    delimiter=delimiter,
                    line_terminator=line_terminator,
                    skip_header=skip_header,
                    enclosed_by=enclosed_by,
                )
                
                results.append({
                    'file': file_path,
                    'table': table_name,
                    'status': 'success',
                    'rows': rows,
                })
                
            except Exception as e:
                print(f"Error importing {imp.get('file', 'unknown')}: {e}")
                results.append({
                    'file': imp.get('file', 'unknown'),
                    'table': imp.get('table', 'unknown'),
                    'status': 'failed',
                    'error': str(e),
                })
        
        # Print summary
        print(f"\n{'=' * 60}")
        print("Batch Import Summary:")
        print(f"{'=' * 60}")
        for r in results:
            status = r['status']
            if status == 'success':
                print(f"  ✓ {r['file']} -> {r['table']}: {r['rows']} rows imported")
            else:
                print(f"  ✗ {r['file']} -> {r['table']}: FAILED - {r['error']}")
        
        success_count = sum(1 for r in results if r['status'] == 'success')
        print(f"\n  Total: {success_count}/{len(results)} imports successful")
        
    finally:
        if connection and connection.is_connected():
            connection.close()
            print("\nDatabase connection closed.")
    
    return results


if __name__ == '__main__':
    if len(sys.argv) > 1 and sys.argv[1] == '--batch':
        if len(sys.argv) < 3:
            print("Usage: python solution.py --batch <config_file.json>")
            sys.exit(1)
        batch_import(sys.argv[2])
    else:
        run_etl_import()